<script>
document.addEventListener('DOMContentLoaded', function() {
  var stripe = Stripe('YOUR_PUBLISHABLE_KEY');

  // Create a PaymentElement with styling
  const elements = stripe.elements();
  const paymentElement = elements.create('payment');
  paymentElement.mount('#payment-element');

  document.getElementById('checkout-form').addEventListener('submit', async (event) => {
    event.preventDefault();

    // Disable the submit button to prevent multiple clicks
    document.querySelector('button[type="submit"]').disabled = true;

    const { error, paymentMethod } = await stripe.createPaymentMethod(
      'card',
      paymentElement,
      {}
    );

    if (error) {
      console.error('[ERROR] Payment method creation failed:', error);
      return;
    }

    // Send the payment method ID to your server
    fetch('/process-payment', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ paymentMethodId: paymentMethod.id }),
    })
    .then(response => response.json())
    .then(data => {
      if (data.error) {
        console.error('[ERROR] Payment processing failed:', data.error);
      } else {
        console.log('Payment processed successfully!');
      }
    })
    .catch(error => console.error('[ERROR] Fetch request failed:', error));
  });
});
</script>
