#### Example Node.js Server-Side Code

Install dependencies:

```sh
npm install express stripe body-parser cors dotenv
```

Configure your environment variables (`.env`):

```plaintext
STRIPE_SECRET_KEY=your_stripe_secret_key
PORT=3000
```

Create the server (`server.js`):

```javascript
const express = require('express');
const bodyParser = require('body-parser');
const cors = require('cors');
require('dotenv').config();

const stripe = require('stripe')(process.env.STRIPE_SECRET_KEY);

const app = express();
app.use(bodyParser.json());
app.use(cors());

// Endpoint to create and confirm payment intent
app.post('/process-payment', async (req, res) => {
  const { paymentMethodId } = req.body;

  try {
    // Create a PaymentIntent with the order amount and currency
    const paymentIntent = await stripe.paymentIntents.create({
      amount: 1099, // Example amount in cents
      currency: 'usd',
      payment_method_types: ['card'],
      description: 'Example charge',
      receipt_email: req.body.email,
    });

    // Confirm the PaymentIntent to finalize the payment
    const paymentConfirmation = await stripe.paymentIntents.confirm(
      paymentIntent.id,
      {
        payment_method: paymentMethodId,
      }
    );

    res.json({
